// Build Serper search queries for finding business leadership
const input = $input.first().json;
const name = input.businessName;
const website = input.website || '';
const domain = website ? new URL(website).hostname.replace('www.', '') : '';

const queries = [
  `${name} owner CEO founder director vlasnik direktor`,
  `${name} ${domain} management team leadership`,
  `${name} LinkedIn`
];

// If we have a domain, also search the site directly
if (domain) {
  queries.push(`site:${domain} about team management contact`);
}

return queries.map(q => ({ json: { query: q, businessName: name } }));

// Run all Serper queries and collect results
const queries = $input.all();
const apiKey = $env.SERPER_API_KEY;
const allResults = [];

for (const item of queries) {
  const query = item.json.query;

  try {
    const response = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://google.serper.dev/search',
      headers: {
        'Content-Type': 'application/json',
        'X-API-KEY': apiKey
      },
      body: JSON.stringify({ q: query, num: 10 })
    });

    const data = typeof response === 'string' ? JSON.parse(response) : response;
    const organic = data.organic || [];

    for (const result of organic) {
      allResults.push({
        source: 'serper',
        title: result.title || '',
        snippet: result.snippet || '',
        url: result.link || '',
        query: query
      });
    }

    // Include knowledge graph if present
    if (data.knowledgeGraph) {
      const kg = data.knowledgeGraph;
      allResults.push({
        source: 'serper',
        title: kg.title || '',
        snippet: JSON.stringify({
          description: kg.description || '',
          attributes: kg.attributes || {},
          website: kg.website || '',
          phone: kg.phone || ''
        }),
        url: kg.website || '',
        query: query
      });
    }
  } catch (e) {
    // Skip failed queries, don't block other results
  }

  // Brief delay between queries
  await new Promise(resolve => setTimeout(resolve, 1000));
}

return [{ json: { results: allResults } }];
